(function (global) {
'use strict';

var EEG_REGISTRY = {
  contactPct: { label:'% Contact', unit:'%', goodDirection:'up', depth:'basic', evidence:'measured',
    cite:'Per-channel contact quality — direct sensor readout' },
  analyzablePct: { label:'% Analyzable', unit:'%', goodDirection:'up', depth:'basic', evidence:'measured',
    cite:'Analyzable coverage after artifact rejection — direct' },
  totalPower: { label:'Total Power', unit:'µV²', goodDirection:'neutral', depth:'advanced', evidence:'measured',
    cite:'Broadband spectral power — direct from the PSD' },
  alphaRel: { label:'α rel', unit:'%', goodDirection:'neutral', depth:'basic', evidence:'validated',
    cite:'Relative alpha power — established EEG band readout' },
  thetaRel: { label:'θ rel', unit:'%', goodDirection:'neutral', depth:'basic', evidence:'validated',
    cite:'Relative theta power — established EEG band readout' },
  alphaTheta: { label:'α/θ', unit:'', goodDirection:'neutral', depth:'advanced', evidence:'emerging',
    cite:'Alpha/theta ratio — published drowsiness/relaxation index, device-dependent' },
  remPct: { label:'REM %', unit:'%', goodDirection:'neutral', depth:'basic', evidence:'validated',
    cite:'EEG-staged REM fraction — EEG is the sleep-staging reference standard' },
  spindleDensity: { label:'Spindles', unit:'/min', goodDirection:'up', depth:'research', evidence:'emerging',
    cite:'Sleep-spindle density (11–16 Hz bursts) — published memory-consolidation marker, device-dependent' },
  frontalAsym: { label:'FAA', unit:'', goodDirection:'neutral', depth:'research', evidence:'experimental',
    cite:'Frontal alpha asymmetry — affective-state composite, EEGDex-derived, weak consumer-grade support' },
  calmScore: { label:'Calm', unit:'', goodDirection:'up', depth:'advanced', evidence:'heuristic',
    cite:'Calm score — heuristic wellness composite, not a validated EEG metric' },
};

var EEG_LABEL_ALIAS = {
  'contact quality':'contactPct',
  '% contact':'contactPct',
  'fraction of the recording with all electrodes in good contact':'contactPct',
  'analyzable':'analyzablePct',
  '% analyzable':'analyzablePct',
  'fraction of the recording usable after artifact rejection':'analyzablePct',
  'total spectral power':'totalPower',
  'total power':'totalPower',
  'broadband eeg power 1–50 hz':'totalPower',
  'relative alpha':'alphaRel',
  'α rel':'alphaRel',
  'alpha-band (8–13 hz) relative power':'alphaRel',
  'relative theta':'thetaRel',
  'θ rel':'thetaRel',
  'theta-band (4–8 hz) relative power':'thetaRel',
  'alpha/theta ratio':'alphaTheta',
  'α/θ':'alphaTheta',
  'ratio of alpha to theta band power':'alphaTheta',
  'rem fraction':'remPct',
  'rem %':'remPct',
  'fraction of total sleep time scored rem from eeg':'remPct',
  'spindle density':'spindleDensity',
  'spindles':'spindleDensity',
  'sleep-spindle count per minute of n2':'spindleDensity',
  'frontal alpha asymmetry':'frontalAsym',
  'faa':'frontalAsym',
  'ln(α right) − ln(α left) over frontal channels (af7/af8)':'frontalAsym',
  'calm score':'calmScore',
  'calm':'calmScore',
  'composite relaxation index blended from band ratios':'calmScore',
};

function _norm(s){ return String(s==null?'':s).toLowerCase().replace(/<[^>]*>/g,'').replace(/\s+/g,' ').trim(); }

/* idForLabel(label) → registry id | null */
function idForLabel(label){
  var k = _norm(label);
  if(EEG_REGISTRY[k]) return k;
  return EEG_LABEL_ALIAS[k] || null;
}

var _META_DENY = { 'date':1, 'start':1, 'end':1, 'source':1, 'sample rate':1, 'recording':1, 'duration':1, 'scenario':1, 'metric':1, 'tier':1, 'channel':1, 'electrode':1 };

/* badgeForLabel(label, fallback) → evidence-dot span | '' (coverage mandate). */
function badgeForLabel(label, fallback){
  if(!global.MetricRegistry) return '';
  var n = _norm(label);
  if(n === '' || n.charAt(0) === '\u2014' || n.charAt(0) === '\u2192') return '';
  var id = idForLabel(label);
  if(!id){
    if(fallback && !_META_DENY[n]) return global.MetricRegistry.badge('experimental','');
    return '';
  }
  var d = global.MetricRegistry.entry(EEG_REGISTRY, id);
  return global.MetricRegistry.badge(d.evidence, d.cite);
}

/* depthForLabel(label) → 'basic'|'advanced'|'research'|null */
function depthForLabel(label){
  var id = idForLabel(label); if(!id) return null;
  return global.MetricRegistry ? global.MetricRegistry.entry(EEG_REGISTRY, id).depth : null;
}

global.EEG_REGISTRY = EEG_REGISTRY;
global.EegRegistry = {
  REGISTRY: EEG_REGISTRY, ALIAS: EEG_LABEL_ALIAS,
  idForLabel: idForLabel, badgeForLabel: badgeForLabel, depthForLabel: depthForLabel
};

})(typeof window !== 'undefined' ? window : globalThis);
